1	const PROCESSING_FEE = 5;
2	
3	export function processScenario(scenario: any): unknown {
4	  const step = scenario.steps[0];
5	  const premium = step.items.length === 0 ? PROCESSING_FEE : 115;
6	  return [{ premium }];
7	}
